sql:
SELECT time
FROM velocity_data
WHERE experiment_id = 1;

SELECT AVG(time) AS average_experiment_time
FROM time_data
WHERE experiment_id = 1;

SELECT COUNT(velocity_id) AS velocity_data_points
FROM velocity_data
WHERE experiment_id = 1;

external_knowledge:
